@startuml
skinparam classAttributeIconSize 0
skinparam classFontStyle bold
skinparam classBackgroundColor #F5F5F5
skinparam classBorderColor #333333
skinparam interfaceBackgroundColor #E6E6FA
skinparam interfaceBorderColor #333333
skinparam packageBackgroundColor #FFFFFF
skinparam packageBorderColor #333333
skinparam arrowColor #333333
skinparam noteBackgroundColor #FFFFCC
skinparam noteBorderColor #333333

class "AbstractFactoryPatternDemo" as AFD {
    void main()
}

class "FactoryProducer" as FP {
    AbstractFactory getFactory()
}

interface "AbstractFactory" as AF {
    Shape getShape()
    Color getColor()
}

class "ShapeFactory" as SF {
    Shape getShape()
}

class "ColorFactory" as CF {
    Color getColor()
}

interface "Shape" as S {
    void draw()
}

interface "Color" as C {
    void fill()
}

class "Circle" as Cir {
    void draw()
}

class "Rectangle" as Rect {
    void draw()
}

class "Square" as Sq {
    void draw()
}

class "Blue" as B {
    void fill()
}

class "Green" as G {
    void fill()
}

class "Red" as R {
    void fill()
}

AFD --> FP : ask
FP --> AF : make
SF --|> AF : extends
CF --|> AF : extends
SF --> S : create
CF --> C : create
Cir --|> S : implement
Rect --|> S : implement
Sq --|> S : implement
B --|> C : implement
G --|> C : implement
R --|> C : implement

package "shape" {
    S
    Cir
    Rect
    Sq
}

package "color" {
    C
    B
    G
    R
}

@enduml
